select from cook_ai_models where deleted_at is null
and model_type = #{modelType}
and status = #{status}
and (name like concat('%', #{keyword}, '%') or provider like concat('%', #{keyword}, '%') or model_code like concat('%', #{keyword}, '%'))
order by model_type asc, is_default desc, id desc

